// https://www.jsdelivr.com/package/npm/highlight.js
// https://cdnjs.com/libraries/highlight.js

(function () {
  const meta = {
    name: 'Highlight',
    version: '1.0.0',
    platform: '0.27.0',
    description: 'Lazy-loads highlight.js and syntax-highlights code blocks on render.',
  };

  function currentTheme() {
    return tw.run.getTiddlerTextRaw('$Theme').replace(/[\[\]]/g, ''); // strip [[ ]]
  }

  // Enable exactly one hljs sheet for the active theme, disabling the other. Doing
  // both (not just enabling one) guarantees a single active sheet regardless of DOM
  // order or load timing. Themes carrying the $ThemeDark tag use the dark sheet.
  function applyHighlightTheme() {
    // The sheets are added on ui.loaded; on a soft ui.reloaded before that they may
    // be absent — skip rather than let enableStyleSheet throw (would fault the plugin).
    if (!document.querySelector('link[data-stylesheet="highlight-light"]')) return;
    let dark = tw.run.getTiddler(currentTheme())?.tags?.includes('$ThemeDark') ?? false;
    tw.core.dom.enableStyleSheet(dark ? 'highlight-dark' : 'highlight-light');
    tw.core.dom.disableStyleSheet(dark ? 'highlight-light' : 'highlight-dark');
  }

  function languageFromTiddlerType(type) {
    switch (type) {
      case 'script/js':
        return 'javascript';
      case 'css':
        return 'css';
      case 'html/template':
        return 'xml';
      case 'json':
        return 'json';
      default:
        return '';
    }
  }

  return {
    meta,
    init() {
      tw.events.subscribe(
        'ui.loaded',
        () => {
          tw.core.dom.addStyleSheet('highlight-light', 'https://cdnjs.cloudflare.com/ajax/libs/highlight.js/11.10.0/styles/atom-one-light.min.css');
          tw.core.dom.addStyleSheet('highlight-dark', 'https://cdnjs.cloudflare.com/ajax/libs/highlight.js/11.10.0/styles/atom-one-dark.min.css');
          tw.core.dom.addScript('highlight-core', 'https://cdnjs.cloudflare.com/ajax/libs/highlight.js/11.10.0/highlight.min.js');
          tw.events.subscribe(
            'script.loaded',
            name => {
              if (name === 'highlight-core') {
                tw.core.dom.addScript('highlight-lang-javascript', 'https://cdnjs.cloudflare.com/ajax/libs/highlight.js/11.10.0/languages/javascript.min.js');
                tw.core.dom.addScript('highlight-lang-css', 'https://cdnjs.cloudflare.com/ajax/libs/highlight.js/11.10.0/languages/css.min.js');
                tw.core.dom.addScript('highlight-lang-xml', 'https://cdnjs.cloudflare.com/ajax/libs/highlight.js/11.10.0/languages/xml.min.js');
                tw.core.dom.addScript('highlight-lang-json', 'https://cdnjs.cloudflare.com/ajax/libs/highlight.js/11.10.0/languages/json.min.js');
                return;
              }
              if (name !== 'highlight-lang-json') return;
              tw.lib.highlight = window.hljs;
              // Since the scripts/css above load after the core has rendered all visible tiddlers,
              //   we have to highlight them now:
              tw.tiddlers.visible.forEach(title => {
                let tiddler = tw.run.getTiddler(title);
                let el = tw.run.getTiddlerElement(tiddler.title);
                el.querySelectorAll('pre code:not([data-highlighted])').forEach(el => tw.lib.highlight?.highlightElement(el, {language: languageFromTiddlerType(tiddler.type)}));
              });
            },
            'Highlight',
          );
          // Apply the correct light/dark highlight for the current theme on load.
          // Set the sheet state DIRECTLY (don't fire theme.switch): firing relied on
          // $CoreThemeManager.themeSwitch running and not early-returning, and left a window
          // where both sheets were enabled (dark, added last, wins) — which is why a light
          // theme could come back with dark code blocks after a reload.
          applyHighlightTheme();
        },
        'Highlight',
      );

      // Re-apply on soft reload too (the highlight <link>s persist in <head>).
      tw.events.subscribe('ui.reloaded', applyHighlightTheme, 'Highlight');

      tw.events.subscribe(
        'tiddler.rendered',
        ({tiddler, newElement}) => {
          newElement.querySelectorAll('pre code:not([data-highlighted])').forEach(el => tw.lib.highlight?.highlightElement(el, {language: languageFromTiddlerType(tiddler.type)}));
        },
        'Highlight',
      );
    },
  };
})();

/**
 * ## Description
 * Provides all theme logic
 * Provides <<ThemeSelector>> widget
 *   listing all tiddlers tagged with $Theme
 */
/**
 * ## Data
 * ```json
 * {
 *   "version": 1.0.1
 * }
 * ```
 */
(function () {
  wireUp('ui.loaded', () => {
    tw.theme = {
      stylesheets: {
        custom: new CSSStyleSheet(),
      },
      getThemeNames,
    };
    document.adoptedStyleSheets.push(tw.theme.stylesheets.custom);
    rebuildRelevanceList();
    themeUpdate();
  });

  wireUp('tiddler.updated', tiddlerChanged);
  // tiddler.deleted: the tiddler is already gone from the store when the event fires,
  // so tag checks return nothing. Check relevance against the registry first, then
  // drop the entry — only rebuild CSS if the deleted tiddler was actually CSS-relevant.
  wireUp('tiddler.deleted', title => {
    const wasRelevant = tiddlerIsThemeRelevant(title);
    addToRelevance(title, false);
    if (wasRelevant) themeUpdate();
  });
  function tiddlerChanged(title) {
    // Capture pre-sync relevance so that a plugin which *loses* its # StyleSheet
    // still triggers a rebuild (it's no longer relevant, but its CSS must be removed).
    const wasRelevant = tiddlerIsThemeRelevant(title);
    if (tw.run.getTiddler(title)?.tags?.includes('$Plugin')) addToRelevance(title, !!tw.run.getTiddlerTextRaw(`${title}::StyleSheet`));
    if (wasRelevant || tiddlerIsThemeRelevant(title)) return themeUpdate();
    if (tiddlerIsATheme(title)) return themesUpdate();
  }
  function addToRelevance(title, present) {
    const list = tw.tmp.themeRelevantTiddlers || (tw.tmp.themeRelevantTiddlers = []);
    const idx = list.indexOf(title);
    if (present && idx === -1) list.push(title);
    else if (!present && idx !== -1) list.splice(idx, 1);
  }

  // Boot population: every tiddler whose text contributes to the @layer cascade.
  // Single source of truth — kept current by themeSwitch (theme + its sheets) and
  // tiddlerChanged (plugins gaining/losing a # StyleSheet section).
  function rebuildRelevanceList() {
    const list = [];
    list.push(...BASE_SHEETS, USER_SHEET, '$Theme');
    // Mirror getThemeStyleSheets()'s fallback so the registry agrees with what
    // buildCss() actually concatenates when $Theme points to a missing tiddler.
    let theme = getCurrentThemeName();
    if (!tw.call('tiddlerExists', theme)) theme = '$CoreThemeLight';
    if (tw.call('tiddlerExists', theme)) {
      list.push(theme);
      list.push(...tw.run.getTiddlerList(theme));
    }
    tw.tiddlers.all.filter(t => t.tags?.includes('$Plugin') && tw.run.getTiddlerTextRaw(`${t.title}::StyleSheet`)).forEach(t => list.push(t.title));
    tw.tmp.themeRelevantTiddlers = [...new Set(list)];
  }

  wireUp('theme.switch', themeSwitch);
  function themeSwitch(theme) {
    if (!theme) return;
    if (!tw.call('tiddlerExists', theme)) return tw.ui.notify(`Unknown theme tiddler '${theme}'!`, 'E');
    // Swap relevance entries before $Theme is rewritten: drop the old theme tiddler
    // and its sheets, add the new ones. Base / user / $Theme / plugin entries stay.
    swapThemeRelevance(getCurrentThemeName(), theme);
    // A theme owns its layout via an optional `# MainLayout` section naming a shared
    // layout tiddler. We persist the choice in the `$Layout` pointer (read at the
    // first paint, before packages load). If it changes, a full reload re-renders the
    // chrome from the pointer; a colour-only switch stays instant.
    let newLayout = tw.core.ui.layoutTitleForTheme(theme);
    let curLayout = (tw.run.getTiddlerTextRaw('$Layout') || '').replace(/[\[\]]/g, '').trim() || '$MainLayout';
    let layoutChanges = newLayout !== curLayout;
    let tiddler = tw.run.getTiddler('$Theme');
    tiddler.text = `[[${theme}]]`;
    delete tiddler.doNotSave;
    tw.run.updateTiddlerHard('$Theme', tiddler);
    if (layoutChanges) {
      let lt = tw.run.getTiddler('$Layout');
      if (lt) {
        lt.text = `[[${newLayout}]]`;
        delete lt.doNotSave;
        tw.run.updateTiddlerHard('$Layout', lt);
      }
    }
    if (tw.run.getTiddler(theme)?.tags?.includes('$ThemeDark')) {
      tw.core.dom.enableStyleSheet('highlight-dark');
      tw.core.dom.disableStyleSheet('highlight-light');
    } else {
      tw.core.dom.enableStyleSheet('highlight-light');
      tw.core.dom.disableStyleSheet('highlight-dark');
    }
    tw.events.send('save.auto');
    // A layout change needs a full reload: on the fresh boot initUI renders the
    // chrome from the (now-persisted) $Layout pointer. (A soft reload would re-eval
    // extension tiddlers and stack duplicate handlers — see core.js subscribe dedup.)
    if (layoutChanges) return tw.events.send('reboot.hard');
    tw.events.send('tiddler.refresh', '$Theme');
    themeUpdate(theme);
    syncThemeSelector(theme);
  }

  // The <<ThemeSelector>> macro bakes the `active` class at render time, and a
  // colour-only switch never re-renders it (only a layout change reboots). Move the
  // highlight directly so every theme picker reflects the new theme — covers picker
  // clicks and command-palette switches alike.
  function syncThemeSelector(theme) {
    document.querySelectorAll('.picker[data-event="theme.switch"] .picker-item').forEach(b => b.classList.toggle('active', b.dataset.value === theme));
  }

  const BASE_SHEETS = ['$BaseReset', '$BaseVariables'];
  const USER_SHEET = '$StyleSheetUser';

  wireUp('ui.reloaded', themeUpdate);
  function themeUpdate() {
    tw.theme.stylesheets.custom.replaceSync(buildCss());
  }

  function buildCss() {
    const layers = {
      base: BASE_SHEETS.map(tw.run.getTiddlerTextRaw),
      plugin: pluginStyles(),
      theme: getThemeStyleSheets().map(tw.run.getTiddlerTextRaw),
      user: [tw.run.getTiddlerTextRaw(USER_SHEET)],
    };
    const header = `@layer ${Object.keys(layers).join(', ')};`;
    const body = Object.entries(layers)
      .map(([name, bodies]) => `@layer ${name} {\n${bodies.filter(Boolean).join('\n')}\n}`)
      .join('\n\n');
    return header + '\n\n' + body;
  }

  // Concatenate CSS from every plugin in the relevance registry that exposes a
  // # StyleSheet section. Disabled plugins ($CodeDisabled) are skipped — their JS
  // doesn't run, so their CSS doesn't apply either. Sorted for stable cascade order.
  function pluginStyles() {
    return [...(tw.tmp.themeRelevantTiddlers || [])]
      .filter(title => !tw.run.getTiddler(title)?.tags?.includes('$CodeDisabled'))
      .sort((a, b) => a.localeCompare(b))
      .map(title => tw.run.getTiddlerTextRaw(`${title}::StyleSheet`))
      .filter(Boolean);
  }

  function tiddlerIsATheme(title) {
    return tw.run.getTiddler(title)?.tags?.includes('$Theme');
  }

  function themesUpdate() {
    tw.events.send('tiddler.refresh', '$Themes');
  }

  // Pure array lookup — the registry is the single source of truth, maintained by
  // rebuildRelevanceList (boot), swapThemeRelevance (theme switch), and addToRelevance
  // (plugin gains/loses # StyleSheet on edit/delete).
  function tiddlerIsThemeRelevant(title) {
    return (tw.tmp.themeRelevantTiddlers || []).includes(title);
  }
  function swapThemeRelevance(oldTheme, newTheme) {
    if (oldTheme && tw.call('tiddlerExists', oldTheme)) {
      addToRelevance(oldTheme, false);
      tw.run.getTiddlerList(oldTheme).forEach(s => addToRelevance(s, false));
    }
    addToRelevance(newTheme, true);
    tw.run.getTiddlerList(newTheme).forEach(s => addToRelevance(s, true));
  }
  function getCurrentThemeName() {
    return tw.run.getTiddlerTextRaw('$Theme').replace(/[\[\]]/g, ''); // Remove possible [[links]]
  }
  function getThemeNames() {
    return tw.run.getTiddlersByTag('$Theme').map(t => t.title);
  }
  function getThemeStyleSheets() {
    let theme = getCurrentThemeName();
    if (!tw.call('tiddlerExists', theme)) {
      tw.ui.notify('Unable to determine theme name from $Theme tiddler! Falling back on $CoreThemeLight', 'W');
      theme = '$CoreThemeLight';
    }
    return tw.run.getTiddlerList(theme);
  }

  tw.extensions.registerMacro(
    'core',
    'ThemeSelector',
    () => {
      let theme = getCurrentThemeName();
      // Items as spans (phrasing content) so the parser doesn't hoist them out
      // of the picker-menu when the macro is embedded in a markdown `<p>`. CSS
      // (`.picker-item { display: block }`) handles the visual layout.
      let items = getThemeNames()
        .sort()
        .map(n => `<span class="picker-item${n === theme ? ' active' : ''}" data-value="${n}">${n.replace(/(^\$)|(Theme)/g, '')}</span>`)
        .join('');
      // Single-line output so the widget can live inside markdown table cells
      return `<span class="picker" data-event="theme.switch">
      <button class="icon picker-trigger" title="Theme" aria-haspopup="true">{{$IconTheme}}</button>
      <span class="picker-menu" hidden>${items}</span>
      </span>`.replace(/\n/g, '');
    },
    {
      description: 'Dropdown to switch the active theme instantly.',
      example: '<<ThemeSelector>>',
    },
  );

  // Dynamic command palette entries — one "Switch theme: X" per installed theme.
  // A provider (re-evaluated at palette render) so newly added themes appear live.
  tw.extensions.registerCommandProvider('themes', () =>
    getThemeNames()
      .sort()
      .map(name => ({
        label: `Switch theme: ${name.replace(/(^\$)|(Theme)/g, '')}`,
        event: 'theme.switch',
        payload: name,
      })),
  );

  function wireUp(event, handler) {
    tw.events.subscribe(event, handler, 'CoreThemeManager');
  }
})();

/**
 * ## Description
 * Generic file drag-and-drop: plugins claim dropped files by filename glob via
 * `tw.run.registerDropHandler('*.workspace.json', (text, file) => {...})`.
 * The most specific (longest) matching pattern wins. Shows a full-screen
 * overlay while a file is dragged over the window.
 *
 * The registration API is installed at plugin LOAD time (this IIFE body), so
 * every other plugin can call `tw.run.registerDropHandler` from its `init()`
 * regardless of plugin order (all plugins load before any init runs).
 */
(function () {
  const meta = {
    name: 'DropZone',
    version: '1.0.0',
    platform: '0.27.0',
    description: 'File drag-and-drop with glob-registered handlers and a drop overlay.',
  };

  // The handler list lives on tw.tmp (not in this closure) so the document
  // listeners — bound once per page — always see the CURRENT registrations,
  // even after a soft reload re-evals this plugin and plugins re-register.
  tw.tmp.dropHandlers = [];
  let dragDepth = 0; // counter avoids overlay flicker when dragging over child elements

  function globToRegex(pattern) {
    return new RegExp('^' + pattern.replace(/[.]/g, '\\$&').replace(/\*/g, '.*') + '$', 'i');
  }
  tw.run.registerDropHandler = function registerDropHandler(pattern, handler) {
    tw.tmp.dropHandlers.push({pattern, rx: globToRegex(pattern), handler});
  };

  function handleDrop(event) {
    const files = Array.from(event.dataTransfer?.files || []);
    if (!files.length) return;
    event.preventDefault();
    dragDepth = 0;
    hideDropOverlay();
    // Most specific pattern wins: '*.workspace.json' (longer) beats '*.json'
    const sorted = [...tw.tmp.dropHandlers].sort((a, b) => b.pattern.length - a.pattern.length);
    files.forEach(file => {
      const match = sorted.find(h => h.rx.test(file.name));
      if (!match) return tw.ui.notify(`No handler for '${file.name}'`, 'W');
      const reader = new FileReader();
      reader.onload = () => match.handler(reader.result, file);
      reader.readAsText(file);
    });
  }
  function showDropOverlay() {
    let el = document.getElementById('drop-overlay');
    if (!el) {
      el = document.createElement('div');
      el.id = 'drop-overlay';
      el.textContent = '⤓ Drop a file to import';
      // Inline styles keep the overlay self-contained (no CSS-tiddler dependency);
      // pointer-events:none so it never intercepts the drop or fires dragleave itself.
      el.style.cssText = 'position:fixed;inset:0;z-index:9999;display:flex;align-items:center;' + 'justify-content:center;background:rgba(0,0,0,0.5);color:#fff;font-size:2em;pointer-events:none;';
      document.body.appendChild(el);
    }
    el.style.display = 'flex';
  }
  function hideDropOverlay() {
    const el = document.getElementById('drop-overlay');
    if (el) el.style.display = 'none';
  }

  const hasFiles = e => Array.from(e.dataTransfer?.types || []).includes('Files');
  function onDragEnter(e) {
    if (!hasFiles(e)) return;
    dragDepth++;
    showDropOverlay();
  }
  function onDragOver(e) {
    if (hasFiles(e)) e.preventDefault(); // required to enable drop
  }
  function onDragLeave(e) {
    if (hasFiles(e) && --dragDepth <= 0) hideDropOverlay();
  }

  return {
    meta,
    start() {
      tw.core.dom.on(document, 'dragenter', onDragEnter, 'DropZone');
      tw.core.dom.on(document, 'dragover', onDragOver, 'DropZone');
      tw.core.dom.on(document, 'dragleave', onDragLeave, 'DropZone');
      tw.core.dom.on(document, 'drop', handleDrop, 'DropZone');
    },
    unload() {
      dragDepth = 0;
      hideDropOverlay();
    },
  };
})();

/**
 * ## Description
 * Dump your entire current workspace — everything under `/ws/<workspace>/` in
 * localStorage — to a single downloadable `<workspace>.workspace.json` file.
 * Keys are stored prefix-stripped so the dump restores into whatever workspace
 * is current, regardless of the source workspace name.
 *
 * To restore, drag a `*.workspace.json` file onto the window. This DELETES and
 * completely overwrites the current workspace (a confirm() guards the wipe),
 * then hard-reboots so everything reloads from the restored localStorage.
 */
(function () {
  const meta = {
    name: 'DumpWorkspace',
    version: '1.0.0',
    platform: '0.27.0',
    description: 'Dump/restore the current workspace as a single JSON file.',
  };

  const FORMAT = 'twikki-workspace-v1';

  function dumpWorkspace() {
    const keys = {};
    // tw.store.keys() returns the current workspace's keys prefix-stripped => portable
    tw.store.keys().forEach(k => (keys[k] = tw.store.exportRaw(k)));
    const data = {format: FORMAT, workspace: tw.workspace, keys};
    const blob = new Blob([JSON.stringify(data, null, 2)], {type: 'application/json'});
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = tw.workspace + '.workspace.json';
    a.click();
    URL.revokeObjectURL(url);
    tw.ui.notify(`Workspace '${tw.workspace}' dumped (${Object.keys(keys).length} keys)`, 'S');
  }

  function restoreWorkspace(text, file) {
    if (!confirm(`This will DELETE and completely overwrite your entire workspace ('${tw.workspace}') with the contents of ${file.name}. Continue?`)) return;
    let data;
    try {
      data = JSON.parse(text);
    } catch {
      return tw.ui.notify('Invalid JSON', 'E');
    }
    if (data.format !== FORMAT || typeof data.keys !== 'object' || !data.keys) return tw.ui.notify('Not a twikki workspace file', 'E');
    tw.store.keys().forEach(k => tw.store.delete(k)); // wipe
    Object.entries(data.keys).forEach(([rel, val]) => tw.store.importRaw(rel, val)); // overwrite
    tw.events.send('reboot.hard'); // reloads everything from the restored store
  }

  return {
    meta,
    init() {
      tw.extensions.registerMacro('dump', 'dumpButton', () => tw.ui.button('{{$IconPush}}', 'workspace.dump', null, 'dump', 'title="Dump entire workspace to a file"'), {
        description: 'Button to dump the entire workspace to a downloadable file.',
        example: '<<dump.dumpButton>>',
      });

      tw.events.subscribe('workspace.dump', dumpWorkspace, 'dumpworkspaceplugin');
      tw.run.registerDropHandler('*.workspace.json', restoreWorkspace);
    },
  };
})();

/**
 * ## Description
 * Editor niceties on top of the core edit round-trip: the Ctrl+Enter
 * save-hotkey in the edit form, and the preview pane (`tw.run.previewTiddler`
 * / the tiddler.preview events — also used by the trash manager and sync log).
 * Without this plugin the plain edit path (click-to-edit, click-save) still
 * works — these are enhancements, per the no-plugin invariant.
 */
(function () {
  const meta = {
    name: 'EditorTools',
    version: '1.0.0',
    platform: '0.27.0',
    description: 'Editor enhancements: Ctrl+Enter save hotkey and the preview pane.',
  };

  // A way of showing a tiddler which may or may not exist
  function previewTiddler(t, template) {
    if (typeof t === 'string') t = tw.run.getTiddler(t);
    let newElement = tw.core.render.createTiddlerElement(t, template || tw.templates.TiddlerPreview);
    tw.core.dom.preview.innerHTML = '';
    tw.core.dom.preview.insertAdjacentElement('afterbegin', newElement);
    tw.core.dom.preview.showModal();
  }
  function closePreview() {
    tw.core.dom.preview.close();
  }

  function onEditorKeydown(e) {
    if (e.ctrlKey && (e.code === 'Enter' || e.code === 'NumpadEnter')) {
      e.preventDefault();
      tw.events.send('form.done');
    }
  }

  return {
    meta,
    init() {
      Object.assign(tw.run, {previewTiddler, closePreview});
      tw.events.subscribe('tiddler.preview', previewTiddler, 'EditorTools');
      tw.events.subscribe('tiddler.preview.close', closePreview, 'EditorTools');
      // `keydown` (not the deprecated `keypress`): keypress is no longer
      // dispatched by automation tools (Playwright, chrome-devtools MCP) so
      // the hotkey is undriveable from tests. `preventDefault()` suppresses
      // the textarea's default Enter→newline insertion.
      if (tw.core.dom.frm) {
        tw.core.dom.on(tw.core.dom.frm, 'keydown', onEditorKeydown, 'EditorTools');
      }
    },
  };
})();

