// `<<macros>>` — sibling to `<<modules>>`/`<<plugins>>`. Walks tw.macros and
// emits one markdown table per namespace. Description + example come from the
// 4th-arg `meta` object passed to registerMacro.
//
// `<<macroExamples>>`
// The example column is live: each example string is rendered through
// renderTWikki so the widget actually executes in the cell (renderTWikki's
// own pass over the outer tiddler does NOT recurse into macro output).
tw.extensions.registerMacro(
  'core',
  'macros',
  () => {
    const sections = [];
    const namespaces = Object.keys(tw.macros).sort();
    for (const ns of namespaces) {
      const bucket = tw.macros[ns];
      if (!bucket || typeof bucket !== 'object') continue;
      const names = Object.keys(bucket)
        .filter(n => typeof bucket[n] === 'function')
        .sort((a, b) => a.toLowerCase().localeCompare(b.toLowerCase()));
      if (!names.length) continue;
      const rows = names.map(n => {
        const fn = bucket[n];
        const call = ns === 'core' ? n : `${ns}.${n}`;
        const desc = fn.description || '–';
        return `| \`${call}\` | ${desc} |`;
      });
      sections.push(`### ${ns}`, '', '| Macro | Description |', '|---|---|', ...rows, '');
    }
    return sections.join('\n');
  },
  {
    description: 'Lists every registered macro with description, grouped by namespace.',
    example: '<<macros>>',
  },
);
tw.extensions.registerMacro(
  'core',
  'macroExamples',
  () => {
    const excludeMacros = ['modules', 'plugins', 'macros', 'macroExamples'];
    const sections = [];
    const namespaces = Object.keys(tw.macros).sort();
    for (const ns of namespaces) {
      const bucket = tw.macros[ns];
      if (!bucket || typeof bucket !== 'object') continue;
      const names = Object.keys(bucket)
        .filter(n => typeof bucket[n] === 'function')
        .sort((a, b) => a.toLowerCase().localeCompare(b.toLowerCase()));
      if (!names.length) continue;
      const rows = names
        .map(n => {
          const fn = bucket[n];
          const call = ns === 'core' ? n : `${ns}.${n}`;
          if (excludeMacros.includes(n)) return;
          const exampleSrc = fn.example || `<<${call}>>`;
          let live;
          try {
            live = tw.core.render.renderTWikki({text: exampleSrc, title: 'macros'});
          } catch (e) {
            live = `<span class="error">${e.message}</span>`;
          }
          if (live.length > 1000) return ''; // live = 'Output too long';
          // Block-widget output (newlines and markdown-table pipes) would break
          // the outer table row — collapse newlines and escape inline pipes.
          live = live.replace(/\n+/g, ' ').replace(/\|/g, '\\|');
          return `| \`${exampleSrc}\` | ${live} |`;
        })
        .filter(r => !!r);
      sections.push(`### ${ns}`, '', '| Macro | Example |', '|---|---|', ...rows, '');
    }
    return sections.join('\n');
  },
  {
    description: 'Lists every registered macro with an example, grouped by namespace.',
    example: '<<macroExamples>>',
  },
);

// Lists the installed core modules (tw.modules) with their metadata as a markdown table,
// including each module's built-for platform and its compatibility with the running
// platform. The `compat` report is attached to each module by the boot-time gate; if the
// platform booted at all, every code module is compatible (else the gate would have
// aborted), so this mostly confirms status and surfaces the built-for version.
tw.extensions.registerMacro(
  'core',
  'modules',
  () => {
    const platform = window.twikki?.version || '–';
    const rows = tw.modules.map(m => {
      const name = m.meta?.name || m.name.replace(/^\//, '').replace(/\.(js|json)$/, '');
      const version = m.meta?.version || '–';
      const c = m.compat;
      const builtFor = c?.exempt ? '–' : m.meta?.platform || c?.required || '–';
      let status;
      if (c?.exempt) status = 'n/a';
      else if (!c) status = '?';
      else if (c.severity === 'ok') status = '✓ OK';
      else if (c.severity === 'warn') status = `⚠ ${c.reason || 'minor mismatch'}`;
      else status = `✗ ${c.reason || 'incompatible'}`;
      return `| ${name} | ${version} | ${m.res.type} | ${builtFor} | ${status} |`;
    });
    return [`Running platform: **v${platform}**`, '', '| Module | Version | Type | Built for | Status |', '|---|---|---|---|---|', ...rows].join('\n');
  },
  {
    description: 'Markdown table of installed core modules with versions and platform-compatibility status.',
    example: '<<modules>>',
  },
);

(function () {
  return {
    meta: {
      name: 'OpenLinksInNewWindow',
      version: '0.0.2',
      platform: '0.27.0',
      author: 'Marc Cawood',
      description: 'Open http(s):// links in markdown in a new window',
      dependencies: ['BaseMarkdown'],
    },
    init() {
      if (!tw.core.markdown?.md) throw new Error('markdown-it not active ($BaseMarkdownPlugin missing or replaced) — OpenLinksInNewWindow disabled!');
    },
    start() {
      // Source: https://www.jsdelivr.com/package/npm/markdown-it-for-inline
      //           https://cdn.jsdelivr.net/npm/markdown-it-for-inline@2.0.1/dist/markdown-it-for-inline.js
      function for_inline_plugin(md, ruleName, tokenType, iterator) {
        function scan(state) {
          for (let blkIdx = state.tokens.length - 1; blkIdx >= 0; blkIdx--) {
            if (state.tokens[blkIdx].type !== 'inline') continue;
            const inlineTokens = state.tokens[blkIdx].children;
            for (let i = inlineTokens.length - 1; i >= 0; i--) {
              if (inlineTokens[i].type !== tokenType) continue;
              iterator(inlineTokens, i);
            }
          }
        }
        md.core.ruler.push(ruleName, scan);
      }
      tw.core.markdown.md.use(for_inline_plugin, 'url_new_win', 'link_open', function (tokens, idx) {
        // Open external links in new window
        if (tokens[idx].attrs[0][1].match(/^https?:/)) tokens[idx].attrSet('target', '_blank');
      });
    },
  };
})();

// Lists every $Plugin-tagged tiddler as a markdown table — sibling to the <<modules>>
// macro for core modules. Loaded plugins come from tw.plugins (populated at boot by
// loadPlugins() in the platform); disabled plugins are excluded from tw.plugins, so the
// table is built from the $Plugin tiddlers themselves and cross-referenced with tw.plugins
// for live meta/status. The leading checkbox enables/disables each plugin.
(() => {
  function pluginStatus(p) {
    if (p.error) return `⚠ err: ${p.error.phase} — ${p.error.message}`;
    const sev = p.compat?.severity;
    if (sev === 'ok') return '✓ OK';
    if (sev === 'exempt') return '–';
    if (sev === 'warn') return `⚠ ${p.compat.reason || 'minor mismatch'}`;
    if (sev === 'block') return `✗ ${p.compat.reason || 'incompatible'}`;
    return '?';
  }

  function enabledCheckbox(source, enabled) {
    const params = `---enc:${tw.core.common.encoder(source)}`;
    return `<input type="checkbox" class="plugin-enabled" data-msg="plugin.toggle" data-params="${params}"${enabled ? ' checked' : ''} title="Enable/disable this plugin"/>`;
  }

  // Flip a plugin's enabled state via the $CodeDisabled tag, then reload so
  // loadPlugins() honours the change (unloadPlugins() tears down the old
  // generation first, so disabling fully removes the plugin's effects). The tag
  // is written with updateTiddlerSilent — a $NoEdit-safe raw upsert that also
  // marks the store dirty, so the ● unsaved indicator shows the change without
  // auto-saving; the user saves to persist it (core.packaging PRESERVED_TAGS then
  // keeps $CodeDisabled across the next forced package load).
  function togglePlugin(source) {
    if (!source) return;
    const t = tw.run.getTiddler(source);
    if (!t) return tw.ui.notify(`Plugin '${source}' not found`, 'E');
    const willDisable = !t.tags.includes('$CodeDisabled');
    if (willDisable) t.tags.push('$CodeDisabled');
    else t.tags = t.tags.filter(tg => tg !== '$CodeDisabled');
    tw.run.updateTiddlerSilent(source, t);
    tw.ui.notify(`Plugin '${source}' ${willDisable ? 'disabled' : 'enabled'} — reload is recommended!`, 'S');
    if (confirm('Would you like to reload?')) {
      tw.core.store.save();
      tw.events.send('reboot.hard');
    }
  }
  tw.events.override('plugin.toggle', togglePlugin);

  // Live meta of one plugin as a bullet list — used in plugin tiddlers' # Meta
  // sections so displayed metadata can never drift from the code's meta object.
  tw.extensions.registerMacro(
    'core',
    'pluginMeta',
    name => {
      const p = (tw.plugins || []).find(p => p.meta?.name === name || p.source === name);
      if (!p) return `<span class="error">Plugin '${name}' not found in registry</span>`;
      const lines = Object.entries(p.meta).map(([k, v]) => `- **${k}**: ${v}`);
      lines.push(`- **package**: ${p.package || '–'}`);
      lines.push(`- **status**: ${pluginStatus(p)}`);
      return lines.join('\n');
    },
    {
      description: "Live meta of one plugin as a bullet list (drift-proof inside the plugin's own # Meta section).",
      example: '<<pluginMeta ExamplePlugin>>',
    },
  );
  tw.extensions.registerMacro(
    'core',
    'plugins',
    () => {
      const platform = window.twikki?.version || '–';
      const loaded = tw.plugins || [];
      const rows = (tw.tiddlers.all || [])
        .filter(t => t.tags?.includes('$Plugin'))
        .slice()
        .sort((a, b) => a.title.localeCompare(b.title))
        .map(t => {
          const p = loaded.find(x => x.source === t.title);
          const enabled = !t.tags?.includes('$CodeDisabled');
          const name = p?.meta?.name || `(${t.title})`;
          const version = p?.meta?.version || '–';
          const pkg = p?.package || t.package || '–';
          const builtFor = p?.meta?.platform || p?.compat?.required || '–';
          const status = enabled ? (p ? pluginStatus(p) : '?') : '⏸ disabled';
          return `| ${enabledCheckbox(t.title, enabled)} | [${name}](#${t.title}) | ${t.title} | ${version} | ${pkg} | ${builtFor} | ${status} |`;
        });
      return [`Running platform: **v${platform}**`, '', '| On | Plugin | Source | Version | Package | Built for | Status |', '|---|---|---|---|---|---|---|', ...rows].join('\n');
    },
    {
      description: 'Markdown table of installed plugins with an enable/disable checkbox, versions, source package, and compatibility status.',
      example: '<<plugins>>',
    },
  );
})();

// Flags $Plugin saves so formDone() can prompt for a hard reload — plugins
// bind live state (event subscriptions, DOM hooks) at boot, so an in-place
// edit needs a re-eval to actually take effect. This is a "validator" in the
// stack-of-validators sense (it runs on save and can throw); it does no
// validation of its own, only side-effects the runtime flag.
tw.extensions.registerValidator({
  name: 'plugin-reload-flag',
  match: t => t.tags?.includes('$Plugin'),
  validate: () => {
    let codeBlocks = tw.core.tiddlers.tiddlerCodeBlocks(t);
    if (codeBlocks.length)
      // TODO: Try, catch, return error <span class="error">
      return codeBlocks.forEach(b => tw.run.executeCodeTiddler(b.text, b.title));
  },
});

/**
  * .SYNOPSIS
  * Show a selection of values
  *
  * .DESCRIPTION
  * Provide a dynamic data-driven HTML <select> box with handler
  *
  * .EXAMPLE
  * Show a selection of 3 fixed colors:
  * <<selector red,green, blue>>
  *
  * .EXAMPLE
  * Show a selection of colors from a datalist tiddler:
  * <<selector {tw.run.getTiddlerTextList('ColorSelection')}>>
  *
  * .EXAMPLE
  * Show a selection of 3 keyval pairs:
  * <<selector #f00:red #0f0:green #00f:blue>>
  *
  * TODO: Create a widget which updates the text/field of a tiddler
  *         This would be great in the $Theme tiddler to directly select a theme
  *         <<selector {tw.theme.getThemeNames()}>>
  */
tw.extensions.registerMacro(
  'core',
  'selector',
  values => {
    if (typeof values === 'string') values = values.split(/,\s?/);
    if (typeof values === 'object' && !Array.isArray(values)) values = Object.keys(values).map(key => ({key, value: values[key]}));
    if (!Array.isArray(values)) throw new Error('No array passed!');
    // Single-line output so the widget can live inside markdown table cells
    return `<select>${values.map(v => '<option value="' + (v?.key || v) + '">' + (v?.value || v) + '</option>').join('')}</select>`;
  },
  {
    description: 'HTML <select> built from a csv string or key:value pairs.',
    example: '<<selector red,green,blue>>',
  },
);

