      description: 'Trash-can button showing the trashed-tiddler count; opens $TrashManager.',
      example: '<<TrashCanIcon>>',
    },
  );
  tw.extensions.registerMacro('core', 'TrashEmptyButton', () => tw.ui.button('Empty Trash', 'tiddlers.trashed.empty', null, 'trashButton'), {
    description: 'Permanently delete all trashed tiddlers (asks first).',
    example: '<<TrashEmptyButton>>',
  });
  tw.extensions.registerMacro('core', 'TrashCanStatus', () => `<span id="trashStatus">${tw.tiddlers.trashed.length} tiddlers in the [trash can](#$TrashedTiddlers)!</span>`, {
    description: 'One-line count of trashed tiddlers.',
    example: '<<TrashCanStatus>>',
  });
  tw.events.subscribe('tiddlers.trashed.empty', emptyTrash);
  function emptyTrash() {
    if (!confirm('Are you sure you want to permanently deleted your trashed tiddlers?')) return;
    tw.tiddlers.trashed = [];
    trashCanRefresh();
    tw.run.autoSave();
  }
  tw.extensions.registerMacro(
    'core',
    'TrashCanContents',
    () => {
      const list = tw.tiddlers.trashed
        .map(
          t => `<li><a data-msg="tiddlers.trashed.preview" data-params="${t.title}">${t.title}</a>
      <a title="Restore Tiddler" data-msg="tiddler.trashed.restore" data-params="${t.title}">🚮</a></li>`,
        )
        .join('\n');
      return `<ul id="trashContents">${list}</ul>`;
    },
    {
      description: 'List of trashed tiddlers with preview/restore links.',
      example: '<<TrashCanContents>>',
    },
  );
  tw.events.subscribe('tiddlers.trashed.preview', trashPreview);
  function trashPreview(title) {
    let tiddler = tw.tiddlers.trashed.find(t => t.title === title);
    tw.run.previewTiddler(tiddler, tw.templates.TiddlerTrashed);
  }

  tw.events.subscribe('tiddler.trashed.destroy', removeTiddlerFromTrash);
  function removeTiddlerFromTrash(title) {
    if (!confirm('Are you sure you want to permanently delete your trashed tiddler?')) return;
    let tiddlerIndex = tw.tiddlers.trashed.findIndex(t => t.title === title);
    tw.tiddlers.trashed.splice(tiddlerIndex, 1);
    trashCanRefresh();
    tw.core.dom.preview.close();
    tw.run.autoSave();
  }

  tw.events.subscribe('tiddler.deleted', trashCanRefresh);
  tw.events.subscribe('trash.refresh', trashCanRefresh);
  function trashCanRefresh() {
    if (tw.core.dom.$('trashContents')) tw.core.dom.$('trashContents').outerHTML = tw.lib.markdown(tw.macros.core.TrashCanContents());
    if (tw.core.dom.$('trashCanIcon')) tw.core.dom.$('trashCanIcon').innerHTML = tw.macros.core.TrashCanIcon();
    if (tw.core.dom.$('trashStatus')) tw.core.dom.$('trashStatus').outerHTML = tw.lib.markdown(tw.macros.core.TrashCanStatus());
    tw.run.rerenderTiddler('$TrashedTiddlers');
  }

  tw.events.subscribe('tiddler.trashed.restore', restoreTiddlerFromTrash);
  function restoreTiddlerFromTrash(title) {
    if (!confirm('Are you sure you want to restore your trashed tiddler? This may overwrite an existing tiddler!')) return;
    let tiddler = tw.tiddlers.trashed.find(t => t.title === title);
    tw.run.addTiddler(tiddler);
    tw.run.reload();
    // So styles, search list etc update
    let tiddlerIndex = tw.tiddlers.trashed.findIndex(t => t.title === title);
    tw.tiddlers.trashed.splice(tiddlerIndex, 1);
    trashCanRefresh();
    tw.run.autoSave();
  }
})();

(function () {
  // [[Title]] / [[Title with spaces]]. Loose by design — anything between
  // `[[` and `]]` on one line. The post-hook only ever sees text nodes
  // outside <pre>/<code>/<a>, so over-matching real prose is the only
  // concern, and the bracket pair is already a strong signal.
  const reLink = /\[\[([^\]\n]+)\]\]/g;

  function transformHtml(html) {
    if (!html || !html.includes('[[')) return html;
    const tpl = document.createElement('template');
    tpl.innerHTML = html;
    const walker = document.createTreeWalker(tpl.content, NodeFilter.SHOW_TEXT);
    const targets = [];
    while (walker.nextNode()) {
      const n = walker.currentNode;
      if (!n.nodeValue.includes('[[')) continue;
      // Skip text inside rendered code, or inside an existing anchor — keeps
      // wikilink syntax literal in code blocks and avoids re-wrapping the
      // label of a link that's already an <a>.
      if (n.parentElement?.closest('pre, code, a')) continue;
      targets.push(n);
    }
    if (!targets.length) return html;
    for (const node of targets) {
      const frag = document.createDocumentFragment();
      const text = node.nodeValue;
      let last = 0;
      reLink.lastIndex = 0;
      let m;
      while ((m = reLink.exec(text)) !== null) {
        if (m.index > last) frag.appendChild(document.createTextNode(text.slice(last, m.index)));
        const ref = m[1];
        const a = document.createElement('a');
        a.href = '#' + ref.replace(/ /g, '%20');
        a.textContent = ref;
        frag.appendChild(a);
        last = m.index + m[0].length;
      }
      if (last < text.length) frag.appendChild(document.createTextNode(text.slice(last)));
      node.replaceWith(frag);
    }
    return tpl.innerHTML;
  }

  return {
    meta: {
      name: 'WikiLinks',
      version: '0.1.0',
      platform: '0.27.0',
      description:
        'Late `renderer.post` pass that turns any surviving `[[Title]]` token in rendered text into an `<a href="#Title">` link. Skips text inside <pre>/<code>/<a> so wikilink syntax inside code blocks (and existing links) stays literal. Catches the cases where a renderer.override produces HTML without going through renderTWikki — e.g. the JSDoc of single-file script/js plugins.',
    },
    init() {
      tw.events.subscribe('renderer.post', transformHtml, 'WikiLinks');
    },
  };
})();

tw.extensions.registerMacro(
  'core',
  'WorkspaceSelect',
  () => {
    let workspace = tw.workspace || tw.storage.get('workspace');
    let items = (tw.storage.get('workspaces') || [])
      .map(n => `<a class="picker-item${n === workspace ? ' active' : ''}" href="?ws=${encodeURIComponent(n)}" rel="noopener" data-value="${n}">${n}</a>`)
      .join('');
    // Single-line output so the widget can live inside markdown table cells.
    // Every child of `.picker-menu` MUST be phrasing content (span/a/button) so
    // the HTML parser doesn't hoist block items out of the surrounding `<p>`
    // wrap that markdown-it adds when the macro lives in a tiddler body — see
    // TagsMacro.js for the same gotcha. CSS makes spans render as blocks.
    return `<span class="picker" data-event="workspace.load.prompt">
    <button class="icon picker-trigger" title="Workspace" aria-haspopup="true">{{$IconWorkspace}}</button>
    <span class="picker-menu" hidden>
      <span class="picker-item picker-action" data-value="">– new workspace –</span>
      ${items}</span>
    </span>`.replace(/\n/g, '');
  },
  {
    description: 'Dropdown to switch or create workspaces.',
    example: '<<WorkspaceSelect>>',
  },
);
tw.extensions.registerMacro('core', 'WorkspaceCreate', () => tw.ui.button('Create Workspace', 'workspace.create.prompt'), {
  description: 'Prompt for and create/clone a workspace.',
  example: '<<WorkspaceCreate>>',
});
if (!tw.tmp.workspaceEvents) {
  tw.tmp.workspaceEvents = 1;
  // Guard against losing unsaved changes when switching/creating a workspace.
  // Matters with auto-save off: a dirty in-memory tiddler would be discarded by
  // the hard reboot (workspace.load) or omitted from a clone. `save` is not
  // gated by auto-save, so OK always persists; Cancel keeps the user put.
  function guardUnsaved() {
    if (!tw.ui.isDirty) return true;
    if (!confirm('You have unsaved changes that would be lost.\n\nOK = save them and continue\nCancel = stay in this workspace')) return false;
    tw.events.send('save');
    return true;
  }
  tw.events.subscribe(
    'workspace.load.prompt',
    workspace => {
      if (!guardUnsaved()) return;
      if (!workspace) workspace = tw.events.send('workspace.create.prompt')[0];
      if (!workspace) return;
      tw.events.send('workspace.load', workspace);
    },
    'WorkspaceWidgets',
  );
  tw.events.subscribe(
    'workspace.create.prompt',
    () => {
      if (!guardUnsaved()) return;
      let workspace = prompt('Enter name for new workspace:');
      if (!workspace) return;
      if (confirm('Would you like to clone this workspace?')) tw.events.send('workspace.clone', workspace);
      else tw.events.send('workspace.create', workspace);
      tw.events.send('tiddler.refresh', '$Workspaces');
      return workspace;
    },
    'WorkspaceWidgets',
  );
}

// Command palette: "Create workspace" plus a dynamic "Switch workspace: X" per
// stored workspace (a provider so the list stays current).
tw.extensions.registerCommand({label: 'Create workspace', event: 'workspace.create.prompt'});
tw.extensions.registerCommandProvider('workspaces', () =>
  (tw.storage.get('workspaces') || []).map(name => ({
    label: `Switch workspace: ${name}`,
    event: 'workspace.load.prompt',
    payload: name,
  })),
);

# Description

Obsidian-style command palette. Ctrl/Cmd+K opens an overlay to run commands
and quick-open notes by name:

- empty input or a `>`-prefixed query → the command list (filtered);
- any other text → ranked note search (reusing `tw.core.search.search`).
  Arrow keys move, Enter runs, Escape closes.

Commands are not defined here — any plugin or macro registers its own via
`tw.extensions.registerCommand({label, event?, payload?, run?})` (or
`registerCommandProvider(key, fn)` for runtime-varying lists). The palette
just reads `tw.commands.all()` on every render.

The `<dialog>` is built in JS (so it can't collide with layout ids). The
document-level keydown is bound once (guarded via `tw.tmp`) and is ignored
while the edit dialog is open, so editing keeps its own keyboard.

# Meta

<<pluginMeta CommandPalette>>

# Code

```javascript
(function () {
  const meta = {
    name: 'CommandPalette',
    version: '1.0.0',
    platform: '0.27.0',
    description: 'Ctrl/Cmd+K palette for actions and tiddler navigation.',
  };

  let dialog;
  let input;
  let results;
  let items = [];
  let selected = 0;

  function wireUp(event, handler) {
    tw.events.subscribe(event, handler, 'CommandPalette');
  }

  function init() {
    document.getElementById('command-palette')?.remove();
    dialog = document.createElement('dialog');
    dialog.id = 'command-palette';
    dialog.innerHTML =
      '<input id="palette-input" type="text" autofocus autocomplete="off" spellcheck="false" ' +
      'placeholder="Search commands and notes…  (&gt; for commands only)" />' +
      '<div id="palette-results"></div>';
    document.body.appendChild(dialog);
    input = dialog.querySelector('#palette-input');
    results = dialog.querySelector('#palette-results');

    input.addEventListener('input', () => {
      selected = 0;
      render();
    });
    input.addEventListener('keydown', onInputKeydown);
    results.addEventListener('click', onResultsClick);
    dialog.addEventListener('close', () => {
      input.value = '';
    });

    // Tracked via tw.core.dom.on so the platform's unloadPlugins() phase
    // tears it down before re-evaluating this plugin. The pre-migration
    // guard idiom (tw.tmp.commandPaletteBound) only prevented re-binding
    // — it never removed the previous IIFE's listener, which kept calling
    // a stale open() with a detached dialog.
    tw.core.dom.on(document, 'keydown', onDocKeydown, 'CommandPalette');
  }

  function onDocKeydown(e) {
    if (e.key !== 'k' || !(e.ctrlKey || e.metaKey)) return;
    if (document.getElementById('new-dialog')?.open) return; // editing owns the keyboard
    e.preventDefault();
    open();
  }

  function open() {
    if (!dialog) return;
    input.value = '';
    selected = 0;
    render();
    if (!dialog.open) dialog.showModal();
    // showModal() runs the dialog focusing steps, which in some engines fire
    // after a synchronous focus() and steal it back to the dialog. Defer to the
    // next frame so the input reliably ends up focused.
    requestAnimationFrame(() => input.focus());
  }

  function buildItems() {
    let q = input.value;
    // `>` forces commands-only (Obsidian convention).
    if (q[0] === '>') return commandItems(q.slice(1).trim().toLowerCase());
    // Empty input → the full command list.
    if (!q.trim()) return commandItems('');
    // Plain text → matching commands first, then matching notes.
    return [...commandItems(q.trim().toLowerCase()), ...noteItems(q)];
  }

  function commandItems(needle) {
    return tw.commands
      .all()
      .filter(c => !needle || c.label.toLowerCase().includes(needle))
      .map(c => ({label: c.label, hint: 'command', run: () => runCommand(c)}));
  }

  function noteItems(q) {
    return tw.core.search
      .search(q, tw.tiddlers.all, {all: false})
      .filter(t => t && t.type) // drop the "No results!" placeholder (no type)
      .slice(0, 50)
      .map(t => ({label: t.title, hint: t.type, run: () => openNote(t.title)}));
  }

  function render() {
    items = buildItems();
    if (selected >= items.length) selected = Math.max(0, items.length - 1);
    if (!items.length) {
      results.innerHTML = '<div class="palette-empty">No matches</div>';
      return;
    }
    results.innerHTML = items
      .map(
        (it, i) =>
          `<div class="palette-row${i === selected ? ' selected' : ''}" data-index="${i}">` +
          `<span class="palette-label">${esc(it.label)}</span>` +
          `<span class="palette-hint">${esc(it.hint || '')}</span></div>`,
      )
      .join('');
    // Keep the keyboard-selected row visible as the selection moves past the
    // edge of the scroll viewport. `nearest` only scrolls when needed (no jump).
    results.querySelector('.palette-row.selected')?.scrollIntoView({block: 'nearest'});
  }

  function onInputKeydown(e) {
    if (e.key === 'ArrowDown') {
      e.preventDefault();
      selected = Math.min(selected + 1, items.length - 1);
      render();
    } else if (e.key === 'ArrowUp') {
      e.preventDefault();
      selected = Math.max(selected - 1, 0);
      render();
    } else if (e.key === 'Enter') {
      e.preventDefault();
      runSelected();
    }
    // Escape is handled natively by <dialog>
  }

  function onResultsClick(e) {
    let row = e.target.closest('.palette-row');
    if (!row) return;
    selected = Number(row.getAttribute('data-index'));
    runSelected();
  }

  function runSelected() {
    let it = items[selected];
    if (!it) return;
    dialog.close();
    it.run();
  }

  function runCommand(c) {
    if (c.run) return c.run();
    tw.events.send(c.event, c.payload);
  }

  function openNote(title) {
    tw.events.send('tiddler.show', title);
    if (tw.tabs) tw.tabs.activate(title);
  }

  function esc(s) {
    return tw.core.common.escapeHtml(String(s));
  }

  return {
    meta,
    init() {
      tw.tmp = tw.tmp || {};
      wireUp('ui.loaded', init);
      wireUp('ui.reloaded', init);
    },
    unload() {
      document.getElementById('command-palette')?.remove();
    },
  };
})();
```

# StyleSheet

```css

/* Command palette — modal `<dialog id="command-palette">` with an input row
   and a scrolling results list. */
dialog#command-palette {
  position: fixed;
  top: 12vh;
  left: 50%;
  transform: translateX(-50%);
  width: min(640px, 92vw);
  max-height: 70vh;
  padding: 0;
  background-color: var(--colbg2);
  color: var(--colfg);
  border: 1px solid var(--col4);
  border-radius: var(--rad1);
  box-shadow: 0 12px 48px rgba(0, 0, 0, 0.55);
  overflow: hidden;
}

#palette-input {
  width: 100%;
  border: none;
  border-bottom: 1px solid var(--col4);
  border-radius: 0;
  background: transparent;
  padding: 14px 16px;
  font-size: 1.05rem;
}

#palette-results {
  max-height: 56vh;
  overflow-y: auto;
  padding: 6px;
}

.palette-row {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 12px;
  padding: 8px 12px;
  border-radius: var(--rad1);
  cursor: pointer;
}

.palette-row.selected,
.palette-row:hover {
  background-color: var(--col3);
  color: var(--colfg); /* theme-aware: var(--col-on-accent) fails on light --col3 (e.g. Kontrast) */
  /* Border keeps the row distinguishable where --col3 matches the dialog
     background (e.g. Kontrast: both #fff) — same trick the filled buttons use. */
  outline: 1px solid var(--col4);
  outline-offset: -1px;
}

.palette-label {
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
}

.palette-hint {
  font-size: 0.72rem;
  color: var(--col1);
  flex: 0 0 auto;
}

